import scala.xml._
import scala.collection.JavaConverters._

case class Config(host: String, port: Int)

object XmlParser {
  def parseXmlConfig(xmlString: String): Config = {
    val xmlNodeSeq = XML.loadString(xmlString).child.asScala
    
    // Extract settings from XML using pattern matching
    val host = (xmlNodeSeq find (_.label == "host")).map(node => (node \ "@value").text).getOrElse("defaultHost")
